async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  for (let i = 0; i < 5; i++) {
    await click(100, 300);
    await page.waitForTimeout(3000);
    const state = await page.evaluate(() => {
      const s = window.__latestGameState;
      const vg = s.nearby_entities.find(e => e.name === 'Village Girl');
      return { pos: s.player_position, dist: vg ? vg.distance : null, on_screen: vg ? vg.on_screen : null, cx: vg ? vg.click_x : null };
    });
    if (state.dist && state.dist <= 3) break;
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    const vg = s.nearby_entities.find(e => e.name === 'Village Girl');
    return { pos: s.player_position, villageGirl: vg ? { dist: vg.distance, on_screen: vg.on_screen, cx: vg.click_x, cy: vg.click_y } : null };
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return finalState;
}

