async (page) => {
  // Set up a continuous combat loop in the browser
  await page.evaluate(() => {
    if (window._combatLoop) clearInterval(window._combatLoop);

    window._combatLoop = setInterval(() => {
      const game = window.game;
      if (!game || !game.player || !game.entities) return;

      const player = game.player;
      const px = player.gridX, py = player.gridY;
      const entities = game.entities.entities;

      // Find nearest rat within 15 tiles
      const mobs = Object.values(entities).filter(e => 
        e && e.type === 3 && e.name && e.name.toLowerCase().includes('rat')
      );

      if (!mobs.length) return;

      const nearest = mobs.map(m => ({
        entity: m,
        dist: Math.abs(m.gridX - px) + Math.abs(m.gridY - py)
      })).sort((a, b) => a.dist - b.dist)[0];

      if (!nearest || nearest.dist > 15) return;

      // Set target
      player.setTarget(nearest.entity);

      // Press arrow key toward the rat
      const dx = nearest.entity.gridX - px;
      const dy = nearest.entity.gridY - py;

      let key;
      if (Math.abs(dx) >= Math.abs(dy)) {
        key = dx > 0 ? 'ArrowRight' : 'ArrowLeft';
      } else {
        key = dy > 0 ? 'ArrowDown' : 'ArrowUp';
      }

      const canvas = document.getElementById('canvas');
      canvas.focus();
      canvas.dispatchEvent(new KeyboardEvent('keydown', { code: key, key: key, bubbles: true }));
      setTimeout(() => {
        canvas.dispatchEvent(new KeyboardEvent('keyup', { code: key, key: key, bubbles: true }));
      }, 100);

    }, 400);

    return 'Combat loop started';
  });

  // Let it run for 20 seconds
  await page.waitForTimeout(20000);

  // Stop loop
  await page.evaluate(() => {
    if (window._combatLoop) clearInterval(window._combatLoop);
  });

  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return gs ? {
      pos: gs.player_position,
      stats: gs.player_stats,
      target: gs.current_target,
      combat: gs.last_combat,
      drops: gs.nearby_entities ? gs.nearby_entities.filter(e => e.type === 4) : []
    } : null;
  });
  return JSON.stringify(state);
}

