async (page) => {
  // Set up automated tree chopper that finds and moves to each tree
  await page.evaluate(() => {
    if (window._chopLoop) clearInterval(window._chopLoop);

    let lastChoppedIds = new Set();
    let chopCount = 0;

    window._chopLoop = setInterval(() => {
      const game = window.game;
      if (!game || !game.player || !game.entities) return;

      const player = game.player;
      const px = player.gridX, py = player.gridY;

      // Find all trees within 15 tiles that haven't been chopped yet
      const trees = Object.values(game.entities.entities)
        .filter(e => e && e.type === 10 && e.name === 'Oak' && !lastChoppedIds.has(e.id))
        .map(e => ({ 
          id: e.id, entity: e,
          dist: Math.abs(e.gridX-px) + Math.abs(e.gridY-py),
          dx: e.gridX-px, dy: e.gridY-py
        }))
        .filter(t => t.dist <= 15)
        .sort((a,b) => a.dist - b.dist);

      if (!trees.length) return;

      const target = trees[0];

      if (target.dist <= 1) {
        // Adjacent to tree - chop it
        let key;
        if (Math.abs(target.dx) >= Math.abs(target.dy)) {
          key = target.dx > 0 ? 'ArrowRight' : 'ArrowLeft';
        } else {
          key = target.dy > 0 ? 'ArrowDown' : 'ArrowUp';
        }
        const canvas = document.getElementById('canvas');
        canvas.focus();
        canvas.dispatchEvent(new KeyboardEvent('keydown', { code: key, key, bubbles: true }));
        setTimeout(() => canvas.dispatchEvent(new KeyboardEvent('keyup', { code: key, key, bubbles: true })), 100);
        lastChoppedIds.add(target.id);
        chopCount++;
        window._chopCount = chopCount;
      } else {
        // Move toward tree using arrow key
        let key;
        if (Math.abs(target.dx) >= Math.abs(target.dy)) {
          key = target.dx > 0 ? 'ArrowRight' : 'ArrowLeft';
        } else {
          key = target.dy > 0 ? 'ArrowDown' : 'ArrowUp';
        }
        const canvas = document.getElementById('canvas');
        canvas.focus();
        canvas.dispatchEvent(new KeyboardEvent('keydown', { code: key, key, bubbles: true }));
        setTimeout(() => canvas.dispatchEvent(new KeyboardEvent('keyup', { code: key, key, bubbles: true })), 100);
      }
    }, 600);
  });

  // Run for 60 seconds
  for (let i = 0; i < 6; i++) {
    await page.waitForTimeout(10000);
    const check = await page.evaluate(() => {
      const gs = window.__latestGameState;
      return gs ? { 
        logs: gs.inventory.filter(i=>i.key==='logs').reduce((s,i)=>s+i.count,0),
        stage: gs.quests.find(q=>q.key==='foresting')?.stage,
        pos: gs.player_position,
        chopCount: window._chopCount || 0
      } : null;
    });
    console.log(`[${(i+1)*10}s]`, JSON.stringify(check));
    if (check && check.stage > 1) break;
  }

  await page.evaluate(() => { if (window._chopLoop) clearInterval(window._chopLoop); });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return gs ? { quest: gs.quests.find(q=>q.key==='foresting'), inventory: gs.inventory, pos: gs.player_position } : null;
  });
  return JSON.stringify(state);
}

