async (page) => {
  // Get Forester exact coords and click
  const coords = await page.evaluate(() => {
    const game = window.game;
    const player = game.player;
    const cam = game.camera;
    const forester = Object.values(game.entities.entities).find(e => e && e.name === 'Forester');
    if (!forester) return null;
    const zoom = (window.innerWidth / 2) / (player.x - cam.x);
    const sx = Math.min(1279, Math.max(0, Math.round((forester.x - cam.x) * zoom)));
    const sy = Math.min(799, Math.max(0, Math.round((forester.y - cam.y) * zoom)));
    return { sx, sy };
  });

  if (!coords) return 'Forester not found';

  await page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: coords.sx, y: coords.sy });
  await page.waitForTimeout(3000);

  const pos = await page.evaluate(() => window.__latestGameState?.player_position);
  const dist = await page.evaluate(() => {
    const s = window.__latestGameState;
    return (s?.nearby_entities || []).find(e => e.name === 'Forester')?.distance;
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return JSON.stringify({coords, pos, dist});
}

